  1→import React, { Suspense, useEffect, useMemo, useRef, useState } from 'react';
  2→import { Category, DataPoint } from '../../types';
  3→import type { CollectionAssignment, MapScope, PointEvent, ProjectedPoint, UserRole } from '../../shared/types';
  4→import {
  5→  BONAMOUSSADI_CENTER,
  6→  CAMEROON_CENTER,
  7→  bonamoussadiLeafletBounds,
  8→  cameroonLeafletBounds,
  9→  isWithinBonamoussadi
 10→} from '../../shared/geofence';
 11→import {
 12→  ChevronDown,
 13→  List,
 14→  Map as MapIcon,
 15→  MapPin,
 16→  Plus,
 17→  ShieldCheck,
 18→  User
 19→} from 'lucide-react';
 20→import VerticalIcon from '../shared/VerticalIcon';
 21→import { categoryLabel as getCategoryLabel, LEGACY_CATEGORY_MAP, VERTICALS } from '../../shared/verticals';
 22→import { apiJson } from '../../lib/client/api';
 23→import { detectLowEndDevice } from '../../lib/client/deviceProfile';
 24→import { getSession } from '../../lib/client/auth';
